module RefModule(in, enable, clear, clk, out);input [5:0] in;
  input enable;
  input clear;
  input clk;
  output [5:0] out;

  reg [5:0] obf_states;

  always @ (posedge clk) begin
    if(enable && clear) begin
      obf_states = 6'b000000;
    end

    else if(enable) begin
      obf_states <= in;
    end
  end

  assign out = obf_states;

endmodule
